"use strict";

import Sharp from "sharp";
import { S3Client, GetObjectCommand } from "@aws-sdk/client-s3";
const S3 = new S3Client({
  region: "ap-northeast-2",
});

const getQuerystring = (querystring, key) => {
  return new URLSearchParams("?" + querystring).get(key);
};

export const imageResize = async (event, context) => {
  console.log("imageResize 실행!!");

  //===================================================================
  //event에서 요청데이터 가져오기
  const { request, response } = event.Records[0].cf;

  //쿼리스트링 가져오기
  //쿼리스트링이 존재하지 않다면 리사이즈 처리할 필요 없으니 원본 반환
  const querystring = request.querystring;
  if (!querystring) {
    console.log("querystring is empty!! return origin");
    return response;
  }

  //uri 가져오기
  const uri = decodeURIComponent(request.uri);
  //파일명이 영어인 경우 : "/samples/chun.jpeg"
  //파일명이 한글인 경우 : "/samples/%E1%84%86%E1%85%A9%E1%84%85%E1%85%A1%E1%86%AB.png"

  //파일 확장자 가져오기
  const extension = uri.match(/(.*)\.(.*)/)[2].toLowerCase();
  console.log("extension", extension);

  //gif는 sharp라이브러리 자체 이슈 존재. 리사이징하지 않고 바로 원본 반환
  if (extension === "gif") {
    console.log("extension is gif!! return origin");
    return response;
  }

  //쿼리스트링 파싱
  const width = Number(getQuerystring(querystring, "w")) || null;
  const height = Number(getQuerystring(querystring, "h")) || null;
  const fit = getQuerystring(querystring, "f");
  const quality = Number(getQuerystring(querystring, "q")) || null;
  console.log({
    width,
    height,
    fit,
    quality,
  });

  //s3 데이터 가져오기
  const s3BucketDomainName = request.origin.s3.domainName;
  let s3BucketName = s3BucketDomainName.replace(".s3.ap-northeast-2.amazonaws.com", "");
  s3BucketName = s3BucketName.replace(".s3.amazonaws.com", "");
  console.log("s3BucketName", s3BucketName);
  const s3Path = uri.substring(1);
  //===================================================================

  //S3에서 이미지 가져오기
  let s3Object = null;
  try {
    s3Object = await S3.send(
      new GetObjectCommand({
        Bucket: s3BucketName,
        Key: s3Path,
      }),
    );
    console.log("S3 GetObject Success");
  } catch (err) {
    console.log("S3 GetObject Fail!! \n" + "Bucket: " + s3BucketName + ", Path: " + s3Path + "\n" + "err: " + err);
    return err;
  }

  //이미지 리사이즈 수행
  const s3Uint8ArrayData = await s3Object.Body.transformToByteArray();

  let resizedImage = null;
  try {
    resizedImage = await Sharp(s3Uint8ArrayData)
      .resize({
        width: width,
        height: height,
        fit: fit,
      })
      .toFormat(extension, {
        quality: quality,
      })
      .toBuffer();
    console.log("Sharp Resize Success");
  } catch (err) {
    console.log("Sharp Resize Fail!! \n" + "Bucket: " + s3BucketName + ", Path: " + s3Path + "\n" + "err: " + err);
    return err;
  }

  //람다엣지에서 응답을 만드는 경우, 응답할 수 있는 body에 크기제한이 있다.
  //base64 인코딩 텍스트로 반환하는 경우 1.3MB(1,048,576 byte)까지 가능.
  const resizedImageByteLength = Buffer.byteLength(resizedImage, "base64");
  console.log("resizedImageByteLength:", resizedImageByteLength);

  //리사이징한 이미지 크기가 1MB 이상인 경우 원본 반환
  if (resizedImageByteLength >= 1048576) {
    console.log("resizedImageByteLength >= 1048576!! return origin");
    return response;
  }

  //리사이징한 이미지 응답할 수 있도록 response 수정
  response.status = 200;
  response.body = resizedImage.toString("base64");
  response.bodyEncoding = "base64";
  console.log("imageResize 종료!!");
  return response;
};

gif도 리사이징 될 수 있게 코드 고쳐줘

`sharp`를 사용하여 GIF 이미지를 처리하는 것은 기본적으로 지원하지 않습니다. `sharp`는 GIF 포맷에 대한 입력만 허용하고, 출력(리사이즈 포함)은 지원하지 않습니다. 이는 `sharp`의 내부 구현과 GIF 포맷의 복잡성 때문입니다. 그러나, GIF 이미지를 리사이징하는 것은 가능하지만 조금 더 복잡한 접근이 필요하고, 특히 Lambda@Edge 같은 환경에서는 추가적인 제약 사항이 있을 수 있습니다. 

### GIF 리사이징을 위한 개요적 접근 방법

1. **GIF를 다른 포맷으로 변환:** 첫 번째 단계는 입력된 GIF를 PNG나 JPEG 같은 다른 포맷으로 변환하는 것입니다. 여기서 중요한 것은 GIF가 일반적으로 애니메이션을 포함할 수 있지만, 단일 이미지 포맷으로 변환할 때는 첫 번째 프레임만 처리됩니다.

2. **변환된 이미지 리사이징:** 변환된 이미지는 `sharp`를 사용해 쉽게 리사이징할 수 있습니다.

3. **응답 준비:** 리사이징된 이미지를 base64 인코딩하여 Lambda@Edge 응답으로 반환할 수 있습니다.

### 코드 수정

```javascript
// S3에서 이미지 가져오기 시 데이터 스트림을 보다 쉽게 처리하기 위한 유틸 함수
const streamToBuffer = async (stream) => {
  return new Promise((resolve, reject) => {
    const chunks = [];
    stream.on('data', (chunk) => chunks.push(chunk));
    stream.on('end', () => resolve(Buffer.concat(chunks)));
    stream.on('error', reject);
  });
};

// 기존 코드...
  // GIF 처리 부분을 제거합니다.
  // 리사이징 수행
  let resizedImage;
  try {
    const s3Stream = s3Object.Body; // S3 객체에서 Body 스트림 가져오기
    let imageBuffer = await streamToBuffer(s3Stream); // 스트림을 버퍼로 변환

    // 이미지 처리 시작
    let sharpInstance = Sharp(imageBuffer);

    if (extension === 'gif') {
      // GIF 경우 다루기 (예제에서는 Sharp로 직접 처리하지만 실제로는 다른 라이브러리 필요)
      console.log("GIF processing is not directly supported by Sharp for output.");
      // 여기에서 추가 로직이 필요합니다. 예를 들어, gifski 라이브러리로 처리할 수 있습니다.
      // Lambda 환경에서 외부 툴 (예: gifski) 사용은 제약사항이 있을 수 있어 주의가 필요합니다.
    } else {
      // 비-GIF 이미지 리사이징
      resizedImage = await sharpInstance
        .resize({
          width: width,
          height: height,
          fit: fit,
        })
        .toFormat(extension, {
          quality: quality,
        })
        .toBuffer();
      console.log("Image processing complete");
    }
  } catch (err) {
    console.log("Image processing failed: \n" + err);
    return err;
  }
// 기존 코드 계속...
```
### 주의사항
- **GIF 애니메이션 처리:** 위 코드는 애니메이션 GIF의 경우 특별한 처리를 하지 않습니다. 실제로 GIF 애니메이션을 리사이즈하려면 각 프레임을 개별적으로 처리하고 다시 GIF로 합치는 과정이 필요합니다. 이는 Lambda@Edge와 같은 서버리스 환경에서는 리소스와 실행 시간의 제약 때문에 다루기 어려울 수 있습니다.
- **실행 환경:** Lambda@Edge에서 외부 도구(예: ImageMagick, gifski 등)를 사용하는 것은 기본적인 Lambda 환경에서 제공되지 않는 라이브러리들을 필요로 할 수 있기 때문에 실현하기 어려울 수 있습니다. AWS Lambda에 패키지를 포함시키거나 커스텀 런타임을 사용하는 등의 추가 작업이 필요할 수 있습니다.

**요약:** `sharp`만을 사용하여 GIF 리사이즈를 직접 수행하는 것은 기능적인 제한 때문에 가능하지 않습니다. 대신, GIF를 처리하기 위해 다른 접근법이나 라이브러리를 고려해야 하며, Lambda@Edge 같은 환경에서는 이에 대한 추가적인 제약이 따릅니다.
